import axios from "axios";
import { useFormik } from "formik";
import { useNavigate } from "react-router-dom";

export function UserRegister() {

    const navigate = useNavigate();

    const formik = useFormik({
        initialValues: {
            UserId: '',
            UserName: '',
            Password: '',
            Email: '',
            Mobile: ''
        },
        onSubmit: (user) => {
            axios.post('http://127.0.0.1:3030/register-user', user)
                .then(() => {
                    alert('User Registered Successfully');
                    navigate('/user-login');
                });
        }
    });

    return (
        <div className="d-flex justify-content-center align-items-center" style={{ height: '90vh' }}>
            <form onSubmit={formik.handleSubmit} className="w-50 border p-4 shadow rounded bg-light">
                <h3 className="text-center text-success mb-4">
                    <i className="bi bi-person-plus-fill me-2"></i>Register User
                </h3>
                <div className="mb-3">
                    <label className="form-label">User ID</label>
                    <input type="text" className="form-control" name="UserId" onChange={formik.handleChange} required />
                </div>
                <div className="mb-3">
                    <label className="form-label">User Name</label>
                    <input type="text" className="form-control" name="UserName" onChange={formik.handleChange} required />
                </div>
                <div className="mb-3">
                    <label className="form-label">Password</label>
                    <input type="password" className="form-control" name="Password" onChange={formik.handleChange} required />
                </div>
                <div className="mb-3">
                    <label className="form-label">Email</label>
                    <input type="email" className="form-control" name="Email" onChange={formik.handleChange} required />
                </div>
                <div className="mb-3">
                    <label className="form-label">Mobile</label>
                    <input type="tel" pattern="[0-9]{10}" className="form-control" name="Mobile" onChange={formik.handleChange} required />
                    <small className="text-muted">10 digit mobile number</small>
                </div>
                <button type="submit" className="btn btn-warning w-100">Register</button>
            </form>
        </div>
    );
}
